931		wtPath := executeBeadWorktreePath(projectRoot, beadID, attemptID)
932	
933		// Serialize the parent-repo mutating pre-dispatch sequence (tracker
934		// commit, caller-dirt checkpoint, base resolution, worktree creation)
935		// under the tracker lock. Without this, concurrent workers race on the
936		// parent's HEAD ref between unlocked CommitTracker and SynthesizeCommit
937		// and surface as "cannot lock ref 'HEAD': is at X but expected Y" CAS
938		// failures (regression: concurrent `ddx work` against the same project).
939		// The lock is held only across the brief pre-dispatch sequence (~1-2s);
940		// agent execution that follows is fully parallel.
941		var baseRev string
942		if err := withTrackerLock(projectRoot, func() error {
943			if mkErr := os.MkdirAll(filepath.Dir(wtPath), 0o755); mkErr != nil {
944				return fmt.Errorf("creating execute-bead worktree parent dir: %w", mkErr)
945			}
946			// Commit beads.jsonl before spawning worktree so the worktree snapshot
947			// includes any bead metadata updates (e.g. spec-id).
948			if err := commitTrackerLocked(projectRoot); err != nil {
949				return err
950			}
951			// Checkpoint any remaining caller dirt as a real commit on the current
952			// branch (FEAT-012 §22, US-126 AC#1). Use a temp-index commit-tree path
953			// here so parent checkout hooks and runtime artifacts cannot fail the
954			// dispatch before the isolated worker worktree exists.
955			if _, err := checkpointPreDispatchDirt(projectRoot, attemptID); err != nil {
956				return fmt.Errorf("pre-execute-bead checkpoint: %w", err)
957			}
958			// Resolve base revision after the tracker + checkpoint commits.
959			rev, err := resolveBase(gitOps, projectRoot, runtime.FromRev)
960			if err != nil {
961				return err
962			}
963			baseRev = rev
964			// Create the isolated worktree. Orphan recovery is the parent's responsibility
965			// (call RecoverOrphans before invoking workers).
966			if err := gitOps.WorktreeAdd(projectRoot, wtPath, baseRev); err != nil {
967				_ = os.RemoveAll(wtPath)
968				return fmt.Errorf("creating isolated worktree: %w", err)
969			}
970			return nil
971		}); err != nil {
972			return nil, err
973		}
974		if err := excludeCleanupMetadataFromWorktreeGit(wtPath); err != nil {
975			_ = gitOps.WorktreeRemove(projectRoot, wtPath)
976			return nil, fmt.Errorf("excluding execute-bead cleanup metadata: %w", err)
977		}
978		if err := WriteExecutionCleanupMetadata(wtPath, ExecutionCleanupMetadata{
979			ProjectRoot:  projectRoot,
980			BeadID:       beadID,
981			AttemptID:    attemptID,
982			WorktreePath: wtPath,
983			Registered:   true,
984			CreatedAt:    time.Now().UTC(),
985		}); err != nil {
986			_ = gitOps.WorktreeRemove(projectRoot, wtPath)
987			return nil, fmt.Errorf("writing execute-bead cleanup metadata: %w", err)
988		}
989		defer func() {
990			_ = gitOps.WorktreeRemove(projectRoot, wtPath)
991		}()
