73	// setupArtifactTestWorktree populates wtPath with a bead store containing one
74	// bead. Optionally includes a governing spec and a required gate.
75	func setupArtifactTestWorktree(t *testing.T, wtPath, beadID, specID string, withGate bool, gateExit int) {
