11	// TestExecuteBeadLandsEvidence is the AC (1) regression test: a simulated
12	// successful execute-bead attempt against a real temp git repo asserts that
13	// (a) after the run returns the working tree is clean, and (b) at least one
14	// file under .ddx/executions/<attempt-id>/ is present in a committed state.
15	// AC (2): the worker's closing_commit_sha still resolves after the merge.
16	func TestExecuteBeadLandsEvidence(t *testing.T) {
17		r := newLandTestRepo(t)
18	
19		// Simulate the orchestrator materializing evidence files in the project root.
20		attemptID := "20260416T181205-aabb1122"
21		evidenceDir := filepath.Join(".ddx", "executions", attemptID)
22		fullDir := filepath.Join(r.dir, evidenceDir)
23		if err := os.MkdirAll(fullDir, 0o755); err != nil {
24			t.Fatal(err)
25		}
26		writeEvidenceFile(t, fullDir, "manifest.json", `{"attempt_id":"`+attemptID+`","bead_id":"ddx-evidence-test"}`)
27		writeEvidenceFile(t, fullDir, "result.json", `{"status":"success","bead_id":"ddx-evidence-test"}`)
28		writeEvidenceFile(t, fullDir, "prompt.md", "# Prompt\nExecute bead ddx-evidence-test")
29	
30		// Create a worker commit (simulates agent output).
31		workerSHA := r.commitOn(r.baseSHA, "feature.txt", "feature content\n", "feat: implement feature [ddx-evidence-test]")
32	
33		// Land with evidence — fast-forward path.
34		req := LandRequest{
35			WorktreeDir:  r.dir,
36			BaseRev:      r.baseSHA,
37			ResultRev:    workerSHA,
38			BeadID:       "ddx-evidence-test",
39			AttemptID:    attemptID,
40			TargetBranch: "main",
41			EvidenceDir:  filepath.ToSlash(evidenceDir),
42		}
43		land, err := Land(r.dir, req, RealLandingGitOps{})
44		if err != nil {
45			t.Fatalf("Land: %v", err)
46		}
47		if land.Status != "landed" {
48			t.Fatalf("expected status=landed, got %q (reason=%q)", land.Status, land.Reason)
49		}
50	
51		// AC (1a): working tree is clean (git status --porcelain is empty).
52		statusOut := r.runGit("status", "--porcelain")
53		if strings.TrimSpace(statusOut) != "" {
54			t.Errorf("AC 1a FAILED: working tree not clean after Land:\n%s", statusOut)
55		}
56	
57		// AC (1b): at least one file under .ddx/executions/<attempt-id>/ is present
58		// in git log for the result or successor commit.
59		logOut := r.runGit("log", "--all", "--oneline", "--name-only")
60		evidenceManifestPath := filepath.ToSlash(filepath.Join(evidenceDir, "manifest.json"))
61		if !strings.Contains(logOut, evidenceManifestPath) {
62			t.Errorf("AC 1b FAILED: %s not found in git log:\n%s", evidenceManifestPath, logOut)
63		}
64	
65		// Evidence commit was created and NewTip advanced past the worker commit.
66		if land.EvidenceCommitSHA == "" {
67			t.Errorf("expected EvidenceCommitSHA to be set")
68		}
69		if land.NewTip == workerSHA {
70			t.Errorf("NewTip should be the evidence commit, not the worker commit")
71		}
72		if land.NewTip != land.EvidenceCommitSHA {
73			t.Errorf("NewTip (%s) != EvidenceCommitSHA (%s)", land.NewTip, land.EvidenceCommitSHA)
74		}
75	
76		// AC (2): closing_commit_sha (the tip that will be recorded) still resolves.
77		checkCmd := exec.Command("git", "-C", r.dir, "cat-file", "-e", land.NewTip)
78		if err := checkCmd.Run(); err != nil {
79			t.Errorf("AC 2 FAILED: closing_commit_sha %s does not resolve: %v", land.NewTip, err)
80		}
81		// The worker's original commit must also still resolve.
82		checkCmd = exec.Command("git", "-C", r.dir, "cat-file", "-e", workerSHA)
83		if err := checkCmd.Run(); err != nil {
84			t.Errorf("AC 2 FAILED: worker commit %s no longer resolves: %v", workerSHA, err)
85		}
86		// Worker commit must be reachable from main.
87		if !r.shaReachable("refs/heads/main", workerSHA) {
88			t.Errorf("worker commit %s not reachable from main", workerSHA)
89		}
90	}
