92	// TestExecuteBeadLandsEvidence_MergePath exercises the merge path (target
93	// branch has advanced since the worker started) and verifies evidence is
94	// committed and the worktree is clean.
95	func TestExecuteBeadLandsEvidence_MergePath(t *testing.T) {
96		r := newLandTestRepo(t)
97	
98		attemptID := "20260416T181206-ccdd3344"
99		evidenceDir := filepath.Join(".ddx", "executions", attemptID)
100		fullDir := filepath.Join(r.dir, evidenceDir)
101		if err := os.MkdirAll(fullDir, 0o755); err != nil {
102			t.Fatal(err)
103		}
104		writeEvidenceFile(t, fullDir, "manifest.json", `{"attempt_id":"`+attemptID+`"}`)
105		writeEvidenceFile(t, fullDir, "result.json", `{"status":"merged"}`)
106	
107		// Worker branches off baseSHA.
108		workerSHA := r.commitOn(r.baseSHA, "feature.txt", "feature\n", "feat: worker")
109	
110		// Sibling advances main. Sync the working tree so it matches siblingSHA's
111		// tree — update-ref alone only moves the ref, leaving the working tree stale.
112		siblingSHA := r.commitOn(r.baseSHA, "sibling.txt", "sibling\n", "feat: sibling")
113		r.runGit("update-ref", "refs/heads/main", siblingSHA)
114		r.runGit("read-tree", "HEAD")
115		r.runGit("checkout-index", "-f", "-a")
116	
117		req := LandRequest{
118			WorktreeDir:  r.dir,
119			BaseRev:      r.baseSHA,
120			ResultRev:    workerSHA,
121			BeadID:       "ddx-evidence-merge",
122			AttemptID:    attemptID,
123			TargetBranch: "main",
124			EvidenceDir:  filepath.ToSlash(evidenceDir),
125		}
126		land, err := Land(r.dir, req, RealLandingGitOps{})
127		if err != nil {
128			t.Fatalf("Land: %v", err)
129		}
130		if land.Status != "landed" {
131			t.Fatalf("expected landed, got %q", land.Status)
132		}
133		if !land.Merged {
134			t.Errorf("expected Merged=true on merge path")
135		}
136	
137		statusOut := r.runGit("status", "--porcelain")
138		if strings.TrimSpace(statusOut) != "" {
139			t.Errorf("working tree not clean after merge-path land:\n%s", statusOut)
140		}
141	
142		if land.EvidenceCommitSHA == "" {
143			t.Errorf("expected EvidenceCommitSHA on merge path")
144		}
145	
146		// Worker commit still resolves (closing_commit_sha contract).
147		checkCmd := exec.Command("git", "-C", r.dir, "cat-file", "-e", workerSHA)
148		if err := checkCmd.Run(); err != nil {
149			t.Errorf("worker SHA %s doesn't resolve after merge: %v", workerSHA, err)
150		}
151		if !r.shaReachable("refs/heads/main", workerSHA) {
152			t.Errorf("worker commit %s not reachable from main after merge", workerSHA)
153		}
154	}
