func evidenceDirHasTrackedFiles(wd, dirRel string) bool {
	out, err := internalgit.Command(context.Background(), wd, "ls-files", "--", filepath.FromSlash(dirRel)).Output()
	return err == nil && len(strings.TrimSpace(string(out))) > 0
}

