package agent

import (
	"context"
	"fmt"
	"os"
	"path/filepath"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/config"
)

// Mock recovery test: manually simulate what the recovery code should do
func TestRecoveryLogic(t *testing.T) {
	projectRoot := t.TempDir()
	dirRel := ".ddx/executions/test-attempt"
	recoveryDir := filepath.Join(projectRoot, dirRel)

	// Simulate writing result.json (which creates the dir)
	resultPath := filepath.Join(recoveryDir, "result.json")
	if err := writeArtifactJSON(resultPath, map[string]string{"status": "test"}); err != nil {
		t.Fatalf("writeArtifactJSON: %v", err)
	}
	fmt.Printf("result.json written: %v\n", mustExist(t, resultPath))

	// Now write prompt.md stub
	promptPath := filepath.Join(recoveryDir, "prompt.md")
	_, e := os.Stat(promptPath)
	fmt.Printf("prompt.md stat err=%v isNotExist=%v\n", e, os.IsNotExist(e))
	if os.IsNotExist(e) {
		if err := os.WriteFile(promptPath, []byte("# stub\n"), 0o644); err != nil {
			fmt.Printf("WriteFile error: %v\n", err)
		} else {
			fmt.Printf("prompt.md written: %v\n", mustExist(t, promptPath))
		}
	}
}

func mustExist(t *testing.T, path string) bool {
	_, err := os.Stat(path)
	return err == nil
}

// Verify that it works the same way inside ExecuteBeadWithConfig
func TestWorktreeLostWithPrint(t *testing.T) {
	projectRoot := setupArtifactTestProjectRoot(t)
	gitOps := &worktreeLostGitOps{
		projectRoot: projectRoot,
		baseRev:     "aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa",
	}
	rcfg := config.NewTestConfigForBead(config.TestBeadConfigOpts{}).Resolve(config.CLIOverrides{Harness: "test-harness"})

	// Wrap to observe
	res, err := ExecuteBeadWithConfig(context.Background(), projectRoot, "ddx-worktree-lost", rcfg, ExecuteBeadRuntime{
		AgentRunner: removeAttemptWorktreeRunner{},
	}, gitOps)
	fmt.Printf("err=%v FailureMode=%s\n", err, res.FailureMode)

	// Now AFTER the call, try to write stubs manually
	recoveryDir := filepath.Join(projectRoot, ".ddx/executions", res.AttemptID)
	promptPath := filepath.Join(recoveryDir, "prompt.md")
	_, e := os.Stat(promptPath)
	fmt.Printf("prompt.md after call: stat err=%v isNotExist=%v\n", e, os.IsNotExist(e))

	// Can we write it now?
	if os.IsNotExist(e) {
		if err := os.WriteFile(promptPath, []byte("manual stub\n"), 0o644); err != nil {
			fmt.Printf("Manual WriteFile error: %v\n", err)
		} else {
			fmt.Println("Manual write succeeded!")
		}
	}
}
